///////////////////////////////////////////////////////////////////////////////
// class : BCTaskEvent
///////////////////////////////////////////////////////////////////////////////

BCTaskEvent::BCTaskEvent()
	: BCMagic(BC_TASKEVENT_MAGIC)
	, ev_attributes(0)
	, ev_tag(NULL)
	, ev_type(0)
	, ev_action(NULL)
	, ev_arg(NULL)
	, ev_sender(NULL)
{
	//
}

BCTaskEvent::BCTaskEvent(
	void *sender,
	BCEventType type,
	LPFN_BCTaskAction action,
	const void *arg)
		: BCMagic(BC_TASKEVENT_MAGIC)
		, ev_attributes(0)
		, ev_tag(NULL)
		, ev_type(type)
		, ev_action(action)
		, ev_arg((void *)arg)
		, ev_sender(sender)
{
	//
}

BCTaskEvent::~BCTaskEvent()
{
	//
}

void BCTaskEvent::Destroy()
{
	delete this;
}

